'use strict'

/**
 * Migration 085: Create password_reset_tokens table
 *
 * Stores one-time tokens generated by admins to allow users to reset
 * their password via the reset-password flow.
 */

const { Pool } = require('pg')

const DB_URL = process.env.DATABASE_URL || 'postgres://policyforge:changeme@127.0.0.1:5432/policyforge_cleaned'

async function run() {
    const pool = new Pool({ connectionString: DB_URL })
    try {
        await pool.query(`
            CREATE TABLE IF NOT EXISTS password_reset_tokens (
                id                  SERIAL PRIMARY KEY,
                user_id             INTEGER NOT NULL REFERENCES users(id),
                token               VARCHAR(255) NOT NULL UNIQUE,
                used                BOOLEAN NOT NULL DEFAULT FALSE,
                expires_at          TIMESTAMP NOT NULL,
                created_at          TIMESTAMP NOT NULL DEFAULT NOW(),
                created_by_user_id  INTEGER
            )
        `)
        console.log('085: Created password_reset_tokens table')
    } finally {
        await pool.end()
    }
}

run().catch(err => { console.error(err.message); process.exit(1) })
